3	#[component]
4	pub fn HoldTimer(expires_at: String, locale: String) -> Element {
5	    let t = shared::i18n::init_translations();
6	    let loc = locale.as_str();
7	
8	    let mut remaining_secs = use_signal(|| compute_remaining(&expires_at));
9	    let expires_clone = expires_at.clone();
10	
11	    use_future(move || {
12	        let expires = expires_clone.clone();
13	        async move {
14	            loop {
15	                gloo_timers::future::TimeoutFuture::new(1_000).await;
16	                let secs = compute_remaining(&expires);
17	                remaining_secs.set(secs);
18	                if secs <= 0 {
19	                    break;
20	                }
21	            }
22	        }
23	    });
24	
25	    let secs = remaining_secs();
26	
27	    if secs <= 0 {
28	        let msg = t.t(loc, "msg.item_released");
29	        rsx! {
30	            div { class: "text-center p-4 rounded-xl bg-red-50 border border-red-300",
31	                span { class: "text-red-600 font-medium", "{msg}" }
32	            }
33	        }
34	    } else {
35	        let minutes = secs / 60;
36	        let seconds = secs % 60;
37	        let display = format!("{:02}:{:02}", minutes, seconds);
38	        let label = t.t(loc, "label.hold_timer");
39	        let wrapper_class = if secs < 60 {
40	            "text-center p-4 rounded-xl bg-red-50 border border-red-300"
41	        } else {
42	            "text-center p-4 rounded-xl bg-amber-50 border border-amber-300"
43	        };
44	        let timer_class = if secs < 60 {
45	            "text-3xl font-bold tabular-nums text-red-600"
46	        } else {
47	            "text-3xl font-bold tabular-nums text-amber-700"
48	        };
49	
50	        rsx! {
51	            div { class: "{wrapper_class}",
52	                span { class: "text-sm text-gray-600", "{label}: " }
53	                span { class: "{timer_class}", "{display}" }
54	            }
55	        }
56	    }
57	}
58	
59	fn compute_remaining(expires_at: &str) -> i64 {
60	    let Ok(expiry) = chrono::NaiveDateTime::parse_from_str(expires_at, "%Y-%m-%dT%H:%M:%S") else {
61	        let Ok(expiry) = chrono::NaiveDateTime::parse_from_str(expires_at, "%Y-%m-%dT%H:%M:%S%.f") else {
62	            return 0;
63	        };
64	        let now = chrono::Utc::now().naive_utc();
65	        return (expiry - now).num_seconds();
66	    };
67	    let now = chrono::Utc::now().naive_utc();
68	    (expiry - now).num_seconds()
69	}
