38	#[post("/checkout", data = "<body>")]
39	pub async fn checkout(
40	    pool: &State<MySqlPool>,
41	    lock_mgr: &State<ReservationLockManager>,
42	    crypto: &State<crate::services::crypto::CryptoConfig>,
43	    user: AuthenticatedUser,
44	    body: Json<CheckoutRequest>,
45	) -> Result<Json<ApiResponse<CheckoutResponse>>, (Status, Json<ApiResponse<()>>)> {
46	    let user_id = user.claims.sub;
47	
48	    // Parse pickup slot times
49	    let slot_start = chrono::NaiveDateTime::parse_from_str(&body.pickup_slot_start, "%Y-%m-%dT%H:%M:%S")
50	        .map_err(|_| {
51	            (
52	                Status::BadRequest,
53	                Json(ApiResponse {
54	                    success: false,
55	                    data: None,
56	                    error: Some("Invalid pickup_slot_start format".into()),
57	                }),
58	            )
59	        })?;
60	
61	    let slot_end = chrono::NaiveDateTime::parse_from_str(&body.pickup_slot_end, "%Y-%m-%dT%H:%M:%S")
62	        .map_err(|_| {
63	            (
64	                Status::BadRequest,
65	                Json(ApiResponse {
66	                    success: false,
67	                    data: None,
68	                    error: Some("Invalid pickup_slot_end format".into()),
69	                }),
70	            )
71	        })?;
72	
73	    // Derive the required prep time from the items actually in the cart.
74	    let cart_id_for_prep = crate::db::cart::get_or_create_cart(pool.inner(), user_id)
75	        .await
76	        .ok();
77	    let prep_minutes = if let Some(cid) = cart_id_for_prep {
78	        crate::db::cart::get_max_prep_time_for_cart(pool.inner(), cid)
79	            .await
80	            .unwrap_or(15)
81	    } else {
82	        15
83	    };
84	
85	    // Check slot availability
86	    if !crate::services::pickup::is_slot_available(slot_start, prep_minutes) {
87	        return Err((
88	            Status::Conflict,
89	            Json(ApiResponse {
90	                success: false,
91	                data: None,
92	                error: Some("Selected pickup slot is no longer available".into()),
93	            }),
94	        ));
95	    }
96	
97	    // Generate voucher code
98	    let voucher_code = crate::services::pickup::generate_voucher_code();
99	
100	    // Get cart items for computing order
101	    let cart_id = crate::db::cart::get_or_create_cart(pool.inner(), user_id)
102	        .await
103	        .map_err(|e| {
104	            (
105	                Status::InternalServerError,
106	                Json(ApiResponse {
107	                    success: false,
108	                    data: None,
109	                    error: Some(format!("Failed to get cart: {}", e)),
110	                }),
111	            )
112	        })?;
113	
114	    let cart_items = crate::db::cart::get_cart_items(pool.inner(), cart_id).await;
115	
116	    if cart_items.is_empty() {
117	        return Err((
118	            Status::BadRequest,
119	            Json(ApiResponse {
120	                success: false,
121	                data: None,
122	                error: Some("Cart is empty".into()),
123	            }),
124	        ));
125	    }
126	
127	    // -----------------------------------------------------------------------
128	    // Acquire concurrency locks for each cart item's SKU + options
129	    // -----------------------------------------------------------------------
130	    let hold_secs: u64 = 600; // 10 minutes
131	    let mut acquired_keys: Vec<String> = Vec::new();
132	
133	    for ci in &cart_items {
134	        let option_ids = get_cart_item_option_ids(pool.inner(), ci.id).await;
135	        let key = reservation_lock::lock_key_for_sku_options(ci.sku_id, &option_ids);
136	
137	        match reservation_lock::try_acquire(
138	            pool.inner(),
139	            lock_mgr.inner(),
140	            &key,
141	            ci.sku_id,
142	            user_id,
143	            ci.quantity,
144	            hold_secs,
145	        )
146	        .await
147	        {
148	            Ok(_handle) => {
149	                acquired_keys.push(key);
150	            }
151	            Err(lock_err) => {
152	                // Roll back all previously acquired locks
153	                for prev_key in &acquired_keys {
154	                    let _ = reservation_lock::release(
155	                        pool.inner(),
156	                        lock_mgr.inner(),
157	                        prev_key,
158	                    )
159	                    .await;
160	                }
161	
162	                let (status, msg) = match &lock_err {
163	                    LockError::AlreadyLocked { .. } => {
164	                        (Status::Conflict, format!("Item locked by another user: {}", lock_err))
165	                    }
166	                    LockError::StockExhausted => {
167	                        (Status::Conflict, format!("Out of stock: {}", lock_err))
168	                    }
169	                    LockError::DatabaseError(_) => {
170	                        (Status::InternalServerError, format!("Lock error: {}", lock_err))
171	                    }
172	                };
173	
174	                return Err((
175	                    status,
176	                    Json(ApiResponse {
177	                        success: false,
178	                        data: None,
179	                        error: Some(msg),
180	                    }),
181	                ));
182	            }
183	        }
184	    }
185	
186	    // Compute pricing
187	    let tax_config = crate::db::store::get_tax_config(pool.inner()).await;
188	    let tax_rate = tax_config.map(|t| t.rate).unwrap_or(0.0);
189	
190	    let line_items: Vec<(f64, i32)> = cart_items.iter().map(|ci| (ci.unit_price, ci.quantity)).collect();
191	    let breakdown = crate::services::pricing::compute_breakdown(&line_items, tax_rate);
192	
193	    let order_number = format!("ORD-{}", chrono::Utc::now().timestamp_millis());
194	    let hold_expires_at = chrono::Local::now().naive_local() + chrono::Duration::minutes(10);
195	    let encrypted_code = crate::services::crypto::encrypt(crypto.inner(), &voucher_code);
196	
197	    // Flatten cart items to (sku_id, quantity, unit_price) for the transactional write.
198	    let items_tuple: Vec<(i64, i32, f64)> = cart_items
199	        .iter()
200	        .map(|ci| (ci.sku_id, ci.quantity, ci.unit_price))
201	        .collect();
202	
203	    // All writes (reservation, order, order_items, voucher, cart clear) execute atomically.
204	    let (reservation_id, order_id) = crate::db::orders::create_checkout(
205	        pool.inner(),
206	        user_id,
207	        slot_start,
208	        slot_end,
209	        &voucher_code,
210	        &encrypted_code,
211	        hold_expires_at,
212	        &order_number,
213	        breakdown.subtotal,
214	        breakdown.tax_amount,
215	        breakdown.total,
216	        &items_tuple,
217	        cart_id,
218	    )
219	    .await
220	    .map_err(|e| {
221	        // Transaction rolled back internally; release the concurrency locks.
222	        let keys = acquired_keys.clone();
223	        let pool_c = pool.inner().clone();
224	        let mgr_c = lock_mgr.inner().clone();
225	        tokio::spawn(async move {
226	            for k in &keys {
227	                let _ = reservation_lock::release(&pool_c, &mgr_c, k).await;
228	            }
229	        });
230	        (
231	            Status::InternalServerError,
232	            Json(ApiResponse {
233	                success: false,
234	                data: None,
235	                error: Some(format!("Checkout failed: {}", e)),
236	            }),
237	        )
238	    })?;
239	
240	    // Associate each acquired lock with this reservation so that confirm_order
241	    // can consume them without restoring stock.
242	    for key in &acquired_keys {
243	        let _ = reservation_lock::associate_reservation(pool.inner(), key, reservation_id).await;
244	    }
245	
246	    Ok(Json(ApiResponse {
247	        success: true,
248	        data: Some(CheckoutResponse {
249	            order_id,
250	            order_number,
251	            voucher_code,
252	            hold_expires_at: hold_expires_at.format("%Y-%m-%dT%H:%M:%S").to_string(),
253	            pickup_slot: format!("{} - {}", slot_start, slot_end),
254	            total: breakdown.total,
255	        }),
256	        error: None,
257	    }))
258	}
