438	pub async fn confirm_order(
439	    pool: &State<MySqlPool>,
440	    lock_mgr: &State<ReservationLockManager>,
441	    user: AuthenticatedUser,
442	    id: i64,
443	) -> Result<Json<ApiResponse<()>>, (Status, Json<ApiResponse<()>>)> {
444	    let order = crate::db::orders::get_order(pool.inner(), id)
445	        .await
446	        .ok_or_else(|| {
447	            (
448	                Status::NotFound,
449	                Json(ApiResponse {
450	                    success: false,
451	                    data: None,
452	                    error: Some("Order not found".into()),
453	                }),
454	            )
455	        })?;
456	
457	    if order.user_id != user.claims.sub {
458	        return Err((
459	            Status::Forbidden,
460	            Json(ApiResponse {
461	                success: false,
462	                data: None,
463	                error: Some("Order does not belong to you".into()),
464	            }),
465	        ));
466	    }
467	
468	    // Confirm the reservation — enforce hold-status and expiry before updating.
469	    if let Some(res_id) = order.reservation_id {
470	        let reservation = crate::db::store::get_reservation(pool.inner(), res_id)
471	            .await
472	            .ok_or_else(|| {
473	                (
474	                    Status::NotFound,
475	                    Json(ApiResponse {
476	                        success: false,
477	                        data: None,
478	                        error: Some("Reservation not found".into()),
479	                    }),
480	                )
481	            })?;
482	
483	        if reservation.status != "Held" {
484	            return Err((
485	                Status::Conflict,
486	                Json(ApiResponse {
487	                    success: false,
488	                    data: None,
489	                    error: Some(format!(
490	                        "Reservation cannot be confirmed: status is '{}' (expected 'Held')",
491	                        reservation.status
492	                    )),
493	                }),
494	            ));
495	        }
496	
497	        let now = chrono::Utc::now().naive_utc();
498	        if reservation.hold_expires_at < now {
499	            let _ = crate::db::store::update_reservation_status(pool.inner(), res_id, "Expired").await;
500	            return Err((
501	                Status::Conflict,
502	                Json(ApiResponse {
503	                    success: false,
504	                    data: None,
505	                    error: Some("Reservation hold has expired; please place a new order".into()),
506	                }),
507	            ));
508	        }
509	
510	        crate::db::store::update_reservation_status(pool.inner(), res_id, "Confirmed")
511	            .await
512	            .map_err(|e| {
513	                (
514	                    Status::BadRequest,
515	                    Json(ApiResponse {
516	                        success: false,
517	                        data: None,
518	                        error: Some(format!("Failed to confirm: {}", e)),
519	                    }),
520	                )
521	            })?;
522	
523	        // Consume the reservation locks so the background expiry job does NOT
524	        // restore inventory for items that have now been sold.
525	        let _ = reservation_lock::consume_by_reservation_id(
526	            pool.inner(),
527	            lock_mgr.inner(),
528	            res_id,
529	        )
530	        .await;
531	    }
532	
533	    Ok(Json(ApiResponse {
534	        success: true,
535	        data: None,
536	        error: None,
537	    }))
538	}
