12	
13	#[derive(Debug, Clone, PartialEq)]
14	pub enum CircuitState {
15	    Closed,
16	    Open,
17	    HalfOpen,
18	}
19	
20	impl std::fmt::Display for CircuitState {
21	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
22	        match self {
23	            CircuitState::Closed => write!(f, "closed"),
24	            CircuitState::Open => write!(f, "open"),
25	            CircuitState::HalfOpen => write!(f, "half_open"),
26	        }
27	    }
28	}
29	
30	pub struct CircuitBreaker {
31	    pub name: String,
32	    pub state: CircuitState,
33	    pub failure_count: u32,
34	    pub success_count: u32,
35	    pub failure_threshold: u32,
36	    pub success_threshold: u32,
37	    pub open_duration_secs: u64,
38	    pub last_failure_at: Option<NaiveDateTime>,
39	    pub last_state_change: NaiveDateTime,
40	}
41	
42	impl CircuitBreaker {
43	    pub fn new(
44	        name: &str,
45	        failure_threshold: u32,
46	        success_threshold: u32,
47	        open_duration_secs: u64,
48	    ) -> Self {
49	        Self {
50	            name: name.to_string(),
51	            state: CircuitState::Closed,
52	            failure_count: 0,
53	            success_count: 0,
54	            failure_threshold,
55	            success_threshold,
56	            open_duration_secs,
57	            last_failure_at: None,
58	            last_state_change: chrono::Utc::now().naive_utc(),
59	        }
60	    }
61	
62	    pub fn can_execute(&mut self) -> bool {
63	        match self.state {
64	            CircuitState::Closed => true,
65	            CircuitState::Open => {
66	                let now = chrono::Utc::now().naive_utc();
67	                let elapsed = now
68	                    .signed_duration_since(self.last_state_change)
69	                    .num_seconds();
70	                if elapsed >= 0 && elapsed as u64 >= self.open_duration_secs {
71	                    tracing::info!(
72	                        circuit = %self.name,
73	                        "Circuit transitioning from Open to HalfOpen"
74	                    );
75	                    self.state = CircuitState::HalfOpen;
76	                    self.success_count = 0;
77	                    self.last_state_change = now;
78	                    true
79	                } else {
80	                    false
81	                }
82	            }
83	            CircuitState::HalfOpen => true,
84	        }
85	    }
86	
87	    pub fn record_success(&mut self) {
88	        self.failure_count = 0;
89	        match self.state {
90	            CircuitState::HalfOpen => {
91	                self.success_count += 1;
92	                if self.success_count >= self.success_threshold {
93	                    tracing::info!(
94	                        circuit = %self.name,
95	                        "Circuit transitioning from HalfOpen to Closed"
96	                    );
97	                    self.state = CircuitState::Closed;
98	                    self.success_count = 0;
99	                    self.last_state_change = chrono::Utc::now().naive_utc();
100	                }
101	            }
102	            CircuitState::Closed => {
103	                // already closed, nothing special
104	            }
105	            CircuitState::Open => {
106	                // shouldn't happen, but reset anyway
107	            }
108	        }
109	    }
110	
111	    pub fn record_failure(&mut self) {
112	        self.failure_count += 1;
113	        self.last_failure_at = Some(chrono::Utc::now().naive_utc());
114	
115	        match self.state {
116	            CircuitState::Closed => {
117	                if self.failure_count >= self.failure_threshold {
118	                    tracing::warn!(
119	                        circuit = %self.name,
120	                        failures = self.failure_count,
121	                        "Circuit transitioning from Closed to Open"
122	                    );
123	                    self.state = CircuitState::Open;
124	                    self.last_state_change = chrono::Utc::now().naive_utc();
125	                }
126	            }
127	            CircuitState::HalfOpen => {
128	                tracing::warn!(
129	                    circuit = %self.name,
130	                    "Circuit transitioning from HalfOpen back to Open"
131	                );
132	                self.state = CircuitState::Open;
133	                self.success_count = 0;
134	                self.last_state_change = chrono::Utc::now().naive_utc();
135	            }
136	            CircuitState::Open => {
137	                // already open
138	            }
139	        }
140	    }
141	}
