144	// ExponentialBackoff
145	// ---------------------------------------------------------------------------
146	
147	pub struct BackoffConfig {
148	    pub initial_delay_ms: u64,
149	    pub max_delay_ms: u64,
150	    pub multiplier: f64,
151	    pub jitter: bool,
152	    pub max_retries: u32,
153	}
154	
155	impl Default for BackoffConfig {
156	    fn default() -> Self {
157	        Self {
158	            initial_delay_ms: 100,
159	            max_delay_ms: 30_000,
160	            multiplier: 2.0,
161	            jitter: true,
162	            max_retries: 5,
163	        }
164	    }
165	}
166	
167	impl BackoffConfig {
168	    pub fn delay_for_attempt(&self, attempt: u32) -> u64 {
169	        let base = self.initial_delay_ms as f64 * self.multiplier.powi(attempt as i32);
170	        let capped = base.min(self.max_delay_ms as f64) as u64;
171	
172	        if self.jitter {
173	            use rand::Rng;
174	            let mut rng = rand::thread_rng();
175	            let jitter_factor: f64 = rng.gen_range(0.75..=1.25);
176	            let jittered = (capped as f64 * jitter_factor) as u64;
177	            jittered.min(self.max_delay_ms)
178	        } else {
179	            capped
180	        }
181	    }
182	}
183	
184	pub async fn execute_with_retry<F, Fut, T, E>(
185	    config: &BackoffConfig,
186	    mut operation: F,
187	) -> Result<T, E>
188	where
189	    F: FnMut() -> Fut,
190	    Fut: Future<Output = Result<T, E>>,
191	    E: std::fmt::Display,
192	{
193	    let mut attempt: u32 = 0;
194	    loop {
195	        match operation().await {
196	            Ok(val) => return Ok(val),
197	            Err(e) => {
198	                if attempt >= config.max_retries {
199	                    tracing::error!(
200	                        attempt = attempt,
201	                        "Max retries exceeded: {}",
202	                        e
203	                    );
204	                    return Err(e);
205	                }
206	                let delay = config.delay_for_attempt(attempt);
207	                tracing::warn!(
208	                    attempt = attempt,
209	                    delay_ms = delay,
210	                    "Retry after error: {}",
211	                    e
212	                );
213	                tokio::time::sleep(tokio::time::Duration::from_millis(delay)).await;
214	                attempt += 1;
215	            }
216	        }
217	    }
218	}
