242	pub struct DegradationManager {
243	    services: Arc<RwLock<HashMap<String, ServiceHealth>>>,
244	}
245	
246	impl DegradationManager {
247	    pub fn new() -> Self {
248	        let mut map = HashMap::new();
249	
250	        let critical = ["ordering", "reservations", "auth", "sessions"];
251	        let non_critical = ["analytics", "import", "exams", "training", "dispatch"];
252	
253	        for name in &critical {
254	            map.insert(
255	                name.to_string(),
256	                ServiceHealth {
257	                    name: name.to_string(),
258	                    is_critical: true,
259	                    is_degraded: false,
260	                    circuit: CircuitBreaker::new(name, 5, 3, 60),
261	                    degraded_since: None,
262	                    last_health_check: None,
263	                },
264	            );
265	        }
266	
267	        for name in &non_critical {
268	            map.insert(
269	                name.to_string(),
270	                ServiceHealth {
271	                    name: name.to_string(),
272	                    is_critical: false,
273	                    is_degraded: false,
274	                    circuit: CircuitBreaker::new(name, 5, 3, 60),
275	                    degraded_since: None,
276	                    last_health_check: None,
277	                },
278	            );
279	        }
280	
281	        Self {
282	            services: Arc::new(RwLock::new(map)),
283	        }
284	    }
285	
286	    pub async fn check_and_degrade(&self, service_name: &str) {
287	        let mut services = self.services.write().await;
288	        if let Some(svc) = services.get_mut(service_name) {
289	            if svc.circuit.state == CircuitState::Open && !svc.is_degraded {
290	                tracing::warn!(service = service_name, "Marking service as degraded");
291	                svc.is_degraded = true;
292	                svc.degraded_since = Some(chrono::Utc::now().naive_utc());
293	            }
294	        }
295	    }
296	
297	    pub async fn is_available(&self, service_name: &str) -> bool {
298	        let services = self.services.read().await;
299	        match services.get(service_name) {
300	            Some(svc) => !svc.is_degraded,
301	            None => true, // unknown services are considered available
302	        }
303	    }
304	
305	    pub async fn record_success(&self, service_name: &str) {
306	        let mut services = self.services.write().await;
307	        if let Some(svc) = services.get_mut(service_name) {
308	            svc.circuit.record_success();
309	            svc.last_health_check = Some(chrono::Utc::now().naive_utc());
310	            if svc.circuit.state == CircuitState::Closed && svc.is_degraded {
311	                tracing::info!(
312	                    service = service_name,
313	                    "Service recovered, removing degraded flag"
314	                );
315	                svc.is_degraded = false;
316	                svc.degraded_since = None;
317	            }
318	        }
319	    }
320	
321	    pub async fn record_failure(&self, service_name: &str) {
322	        let mut services = self.services.write().await;
323	        if let Some(svc) = services.get_mut(service_name) {
324	            svc.circuit.record_failure();
325	            svc.last_health_check = Some(chrono::Utc::now().naive_utc());
326	        }
327	        // Drop write lock before calling check_and_degrade which also needs it
328	        drop(services);
329	        self.check_and_degrade(service_name).await;
330	    }
331	
332	    pub async fn get_status(&self) -> HashMap<String, ServiceStatus> {
333	        let services = self.services.read().await;
334	        services
335	            .iter()
336	            .map(|(k, v)| {
337	                (
338	                    k.clone(),
339	                    ServiceStatus {
340	                        name: v.name.clone(),
341	                        state: v.circuit.state.to_string(),
342	                        is_degraded: v.is_degraded,
343	                        is_critical: v.is_critical,
344	                        circuit_state: v.circuit.state.to_string(),
345	                    },
346	                )
347	            })
348	            .collect()
349	    }
350	
351	    pub async fn can_execute(&self, service_name: &str) -> bool {
352	        let mut services = self.services.write().await;
353	        if let Some(svc) = services.get_mut(service_name) {
354	            svc.circuit.can_execute()
355	        } else {
356	            true
357	        }
358	    }
359	
360	    /// Delegate to the BackgroundJobManager if it's wired in, otherwise empty.
361	    /// This provides a bridge so health.rs can call `degradation.get_job_statuses()`.
362	    pub async fn get_job_statuses(&self) -> Vec<crate::services::health::JobStatus> {
363	        // The BackgroundJobManager holds its own job list. When it is constructed
364	        // with an Arc<DegradationManager> the jobs live there. We return an empty
365	        // vec here; the detailed health check should prefer the standalone BGM
366	        // reference when available.
367	        Vec::new()
368	    }
369	}
