457	
458	pub struct BackgroundJob {
459	    pub name: String,
460	    pub is_enabled: bool,
461	    pub is_critical: bool,
462	    pub interval_secs: u64,
463	    pub last_run: Option<NaiveDateTime>,
464	    pub last_error: Option<String>,
465	    pub consecutive_failures: u32,
466	    pub max_failures_before_disable: u32,
467	}
468	
469	pub struct BackgroundJobManager {
470	    jobs: Arc<RwLock<HashMap<String, BackgroundJob>>>,
471	    degradation: Arc<DegradationManager>,
472	}
473	
474	impl BackgroundJobManager {
475	    pub fn new(degradation: Arc<DegradationManager>) -> Self {
476	        Self {
477	            jobs: Arc::new(RwLock::new(HashMap::new())),
478	            degradation,
479	        }
480	    }
481	
482	    pub async fn register_job(
483	        &self,
484	        name: &str,
485	        interval_secs: u64,
486	        is_critical: bool,
487	        max_failures: u32,
488	    ) {
489	        let mut jobs = self.jobs.write().await;
490	        jobs.insert(
491	            name.to_string(),
492	            BackgroundJob {
493	                name: name.to_string(),
494	                is_enabled: true,
495	                is_critical,
496	                interval_secs,
497	                last_run: None,
498	                last_error: None,
499	                consecutive_failures: 0,
500	                max_failures_before_disable: max_failures,
501	            },
502	        );
503	    }
504	
505	    pub async fn should_run(&self, name: &str) -> bool {
506	        let jobs = self.jobs.read().await;
507	        let job = match jobs.get(name) {
508	            Some(j) => j,
509	            None => return false,
510	        };
511	
512	        if !job.is_enabled {
513	            return false;
514	        }
515	
516	        // Check if the corresponding service is degraded
517	        let service_name = match name {
518	            "session_cleanup" => "sessions",
519	            "reservation_expiry" => "reservations",
520	            "offer_expiry" => "ordering",
521	            "analytics_snapshot" => "analytics",
522	            "lock_cleanup" => "reservations",
523	            _ => name,
524	        };
525	
526	        if !self.degradation.is_available(service_name).await {
527	            return false;
528	        }
529	
530	        match job.last_run {
531	            None => true,
532	            Some(last) => {
533	                let now = chrono::Utc::now().naive_utc();
534	                let elapsed = now.signed_duration_since(last).num_seconds();
535	                elapsed >= 0 && elapsed as u64 >= job.interval_secs
536	            }
537	        }
538	    }
539	
540	    pub async fn record_job_success(&self, name: &str) {
541	        let mut jobs = self.jobs.write().await;
542	        if let Some(job) = jobs.get_mut(name) {
543	            job.last_run = Some(chrono::Utc::now().naive_utc());
544	            job.consecutive_failures = 0;
545	            job.last_error = None;
546	        }
547	    }
548	
549	    pub async fn record_job_failure(&self, name: &str, error: &str) {
550	        let service_name = match name {
551	            "session_cleanup" => "sessions",
552	            "reservation_expiry" => "reservations",
553	            "offer_expiry" => "ordering",
554	            "analytics_snapshot" => "analytics",
555	            "lock_cleanup" => "reservations",
556	            _ => name,
557	        };
558	
559	        let mut jobs = self.jobs.write().await;
560	        if let Some(job) = jobs.get_mut(name) {
561	            job.consecutive_failures += 1;
562	            job.last_error = Some(error.to_string());
563	            job.last_run = Some(chrono::Utc::now().naive_utc());
564	
565	            if job.consecutive_failures >= job.max_failures_before_disable {
566	                tracing::error!(
567	                    job = name,
568	                    failures = job.consecutive_failures,
569	                    "Auto-disabling job after exceeding max failures"
570	                );
571	                job.is_enabled = false;
572	            }
573	        }
574	        drop(jobs);
575	
576	        self.degradation.record_failure(service_name).await;
577	    }
578	
579	    pub async fn get_job_statuses(&self) -> Vec<crate::services::health::JobStatus> {
580	        let jobs = self.jobs.read().await;
581	        jobs.values()
582	            .map(|j| {
583	                let next_run = j.last_run.map(|lr| {
584	                    let next =
585	                        lr + chrono::Duration::seconds(j.interval_secs as i64);
586	                    next.format("%Y-%m-%dT%H:%M:%S").to_string()
587	                });
588	                crate::services::health::JobStatus {
589	                    name: j.name.clone(),
590	                    last_run: j
591	                        .last_run
592	                        .map(|t| t.format("%Y-%m-%dT%H:%M:%S").to_string()),
593	                    next_run,
594	                    is_enabled: j.is_enabled,
595	                    last_error: j.last_error.clone(),
596	                }
597	            })
598	            .collect()
599	    }
600	
601	    pub async fn enable_job(&self, name: &str) {
602	        let mut jobs = self.jobs.write().await;
603	        if let Some(job) = jobs.get_mut(name) {
604	            job.is_enabled = true;
605	            job.consecutive_failures = 0;
606	            tracing::info!(job = name, "Job re-enabled");
607	        }
608	    }
609	
610	    pub async fn disable_job(&self, name: &str) {
611	        let mut jobs = self.jobs.write().await;
612	        if let Some(job) = jobs.get_mut(name) {
613	            job.is_enabled = false;
614	            tracing::info!(job = name, "Job disabled");
615	        }
616	    }
617	
618	    pub async fn get_due_jobs(&self) -> Vec<String> {
619	        let jobs = self.jobs.read().await;
620	        let mut due = Vec::new();
621	        let now = chrono::Utc::now().naive_utc();
622	        for (name, job) in jobs.iter() {
623	            if !job.is_enabled {
624	                continue;
625	            }
626	            let is_due = match job.last_run {
627	                None => true,
628	                Some(last) => {
629	                    let elapsed = now.signed_duration_since(last).num_seconds();
630	                    elapsed >= 0 && elapsed as u64 >= job.interval_secs
631	                }
632	            };
633	            if is_due {
634	                due.push(name.clone());
635	            }
636	        }
637	        due
638	    }
639	}
