8	// ---------------------------------------------------------------------------
9	// AuthenticatedUser -- any logged-in user
10	// ---------------------------------------------------------------------------
11	
12	/// Request guard that requires a valid HMAC-signed session cookie.
13	///
14	/// This is the sole authentication path — there is no JWT bearer fallback.
15	/// Every authenticated request must present a `brewflow_session` cookie whose
16	/// signature is valid, whose DB session exists, and whose `last_activity` is
17	/// within the 30-minute idle timeout.
18	pub struct AuthenticatedUser {
19	    pub claims: Claims,
20	}
21	
22	#[rocket::async_trait]
23	impl<'r> FromRequest<'r> for AuthenticatedUser {
24	    type Error = &'static str;
25	
26	    async fn from_request(request: &'r Request<'_>) -> Outcome<Self, Self::Error> {
27	        match try_cookie_auth(request).await {
28	            Some(user) => Outcome::Success(user),
29	            None => Outcome::Error((Status::Unauthorized, "Valid session cookie required")),
30	        }
31	    }
32	}
33	
34	// ---------------------------------------------------------------------------
35	// Cookie-based auth helper
36	// ---------------------------------------------------------------------------
37	
38	/// Attempt to authenticate via the `brewflow_session` cookie.
39	///
40	/// 1. Read the cookie value
41	/// 2. Verify the HMAC signature
42	/// 3. Look up the session in MySQL
43	/// 4. Check idle timeout
44	/// 5. Touch session (update last_activity)
45	/// 6. Rotate session ID if needed
46	/// 7. Load user roles and build Claims
47	async fn try_cookie_auth(request: &Request<'_>) -> Option<AuthenticatedUser> {
48	    // Check for the cookie FIRST — no DB or state lookup needed for this step.
49	    // Returning None here produces 401 without touching the database, which also
50	    // makes unauthenticated-request tests work without a live DB pool.
51	    let cookie = request.cookies().get("brewflow_session")?;
52	
53	    let session_config = request.rocket().state::<SessionConfig>()?;
54	    let pool = request.rocket().state::<MySqlPool>()?;
55	
56	    let session_id = crate::services::session::verify_cookie(session_config, cookie.value())?;
57	
58	    let session = crate::db::sessions::get_session(pool, &session_id).await?;
59	
60	    // Check idle timeout
61	    let now = chrono::Utc::now().naive_utc();
62	    let idle_secs = now
63	        .signed_duration_since(session.last_activity)
64	        .num_seconds();
65	    if idle_secs < 0 || idle_secs as u64 > session_config.idle_timeout_secs {
66	        // Session expired -- clean it up silently.
67	        let _ = crate::db::sessions::delete_session(pool, &session.session_id).await;
68	        return None;
69	    }
70	
71	    // Touch session (renews last_activity for idle-timeout tracking)
72	    let _ = crate::db::sessions::touch_session(pool, &session.session_id).await;
73	
74	    // Rotate session ID if the rotation interval has elapsed.
75	    // A new session_id is inserted into the DB and a fresh signed cookie is
76	    // set on the current request so the client receives it in the response.
77	    let active_session_id = if crate::services::session::should_rotate(session.rotated_at, session_config) {
78	        let new_id = crate::services::session::create_session_id();
79	        if crate::db::sessions::rotate_session(pool, &session.session_id, &new_id)
80	            .await
81	            .is_ok()
82	        {
83	            let signed = crate::services::session::sign_cookie(session_config, &new_id);
84	            let new_cookie = rocket::http::Cookie::build(("brewflow_session", signed))
85	                .http_only(true)
86	                .same_site(rocket::http::SameSite::Strict)
87	                .secure(true)
88	                .path("/")
89	                .max_age(rocket::time::Duration::seconds(
90	                    session_config.idle_timeout_secs as i64,
91	                ));
92	            request.cookies().add(new_cookie);
93	            new_id
94	        } else {
95	            session.session_id.clone()
96	        }
97	    } else {
98	        session.session_id.clone()
99	    };
100	    let _ = active_session_id; // used only for the cookie set above
101	
102	    // Load user roles
103	    let roles = crate::db::users::get_user_roles(pool, session.user_id).await;
104	    let user = crate::db::users::find_by_id(pool, session.user_id).await?;
105	
106	    let claims = Claims {
107	        sub: session.user_id,
108	        username: user.username,
109	        roles,
110	        exp: 0, // Not applicable for session-based auth
111	    };
112	
113	    Some(AuthenticatedUser { claims })
114	}
115	
